// OpenCL kernel for mixbench - translated from OpenMP implementation

#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 enabled
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 enabled
#endif

__kernel void benchmark_func(class_T seed, __global class_T* data) {
    size_t global_id = get_global_id(0);

    class_T f = seed;
    class_T sum = (class_T)0;

    #if ELEMENTS_PER_THREAD > 0
    #define EPT ELEMENTS_PER_THREAD
    #else
    #define EPT 1
    #endif

    #if FUSION_DEGREE > 0
    #define FD FUSION_DEGREE
    #else
    #define FD 1
    #endif

    #if COMPUTE_ITERATIONS > 0
    #define CI COMPUTE_ITERATIONS
    #else
    #define CI 1
    #endif

    #ifdef BLOCK_STRIDED
    size_t stride = blockdim;
    #else
    size_t stride = 1;
    #endif

    size_t base_idx = global_id * EPT * FD * stride;

    for (int fd = 0; fd < FD; fd++) {
        for (int ei = 0; ei < EPT; ei++) {
            size_t idx = base_idx + (fd * EPT + ei) * stride;
            class_T t = data[idx];

            for (int j = 0; j < CI; j++) {
                t = t * t + f;
            }

            sum += t;
        }
    }

    data[global_id] = sum;
}
